// If name is even number of letters, can't get them all in pairs, so need this 
//one-letter map for the last letter
const last_letter_map = [1, 2, 2, 2, 2, 3, 3, 3, 4, 4, 4, 5, 5, 5, 6, 7, 7, 7, 7, 8, 8, 8, 8, 8, 9, 9];

function getCubeCode() {
    const cubeNumberEl = document.getElementById('cube-code');
    const author = document.getElementById('author').value
        .toUpperCase()
        .replace(/[.,\/#!$%\^&\*;:{}=\-_`~()]/g, "")
        .replace(/\s+/g, '');
    const lengthInput = document.getElementById('total-cutter-length');
    let numberOfCharactersToDisplay = parseInt(lengthInput.value, 10);

    if (author.length < 3) {
        cubeNumberEl.innerHTML = "";
        return '';
    }
    let cubeCode = author[0] + getSecondAndThirdCharOfCubeCode(author[0], author[1], author[2]);

    // Use sCubeAdditionalLookUpTable to get numbers for PAIRS of additional 
    // characters. Last letter of odd-length names never processed!
    let remainingName = author.substring(3, author.length);
    for (let i = 0; i < remainingName.length/2 + 2; i+=2) {
        // If we're at the last letter and it can't be a pair...
        if (remainingName[i+1] == undefined && remainingName[i] != undefined) { 
            // Add a 1 first, to maintain alphabetical order with names
            // that have an 20 to 99 pair here
            cubeCode += "1";
            // Then, if user wants an additional number based on this
            // last, not-paired letter, use the last letter map
            cubeCode += last_letter_map[asNum(remainingName[i]) - 1];
            // tbh I'm not sure if this always maintains alphabetical
            // order, though...
            break; 
        } else if (remainingName[i] != undefined && remainingName[i+1] != undefined) {
            cubeCode += getAdditionalPair(remainingName[i], remainingName[i+1]);
       }
    }

    // If user requests more characters than we have...
    if (cubeCode.length < numberOfCharactersToDisplay) {
        numberOfCharactersToDisplay = cubeCode.length;
    }
    cubeNumberEl.innerHTML = cubeCode.substring(0, numberOfCharactersToDisplay);
}
function asCubeNum(letter1, letter2) {
    let num = 0;
    let multiplier = letter1.charCodeAt(0) - 64 - 1;
    num = num + (multiplier * 26);
    num = num + letter2.charCodeAt(0) - 64 - 1;
    return num;
}
function getSecondAndThirdCharOfCubeCode(firstChar, secondChar, thirdChar) {
    let mapToUse = sCubeLookUpTables[firstChar];
    return mapToUse[asCubeNum(secondChar, thirdChar)];
}
// C => 3
function asNum(letter) {
    return Number(letter.charCodeAt(0) - 64);
}
function getAdditionalPair(letter1, letter2) {
    return sCubeAdditionalLookUpTable[asCubeNum(letter1, letter2)];
}